INSERT INTO books (title, author, publisher, year, pages, category, language, synopsis, moral) VALUES
  ('Menggapai Bintang','A. Samad Said','Dewan Bahasa dan Pustaka',1990,80,'Novel','Melayu','Sebuah kisah yang mengisahkan perjalanan hidup penuh cabaran dan pengorbanan. Pengarang membawa pembaca menyelami dunia yang kaya dengan emosi dan pengalaman tentang Bintang.','Ketabahan dan kesabaran adalah kunci kejayaan dalam setiap aspek kehidupan.'),
  ('Menggapai Bulan','Shahnon Ahmad','PTS Publications & Distributors',1991,89,'Cerpen','Melayu','Karya ini menggambarkan kehidupan manusia yang sentiasa mencari erti kehidupan yang sejati. Satu bacaan yang menyentuh jiwa dan membuka minda tentang kepentingan Bulan.','Kasih sayang, perpaduan dan semangat gotong-royong membina masyarakat yang harmoni dan sejahtera.'),
  ('Menggapai Matahari','Usman Awang','Karangkraf Sdn. Bhd.',1992,98,'Puisi','Melayu','Sebuah novel yang mengisahkan tentang semangat dan ketabahan seorang individu dalam menghadapi rintangan hidup demi mencapai impian berkaitan Matahari.','Ilmu pengetahuan dan pendidikan adalah pelaburan terbaik untuk masa depan yang cemerlang.'),
  ('Menggapai Langit','Arenawati','Fajar Bakti Sdn. Bhd.',1993,107,'Biografi','Melayu','Menerusi halaman demi halaman, pembaca akan dibawa menyelami cerita yang penuh intrik dan emosi yang mendalam berkaitan Langit.','Kejujuran, integriti dan amanah adalah nilai-nilai murni yang perlu diamalkan dalam kehidupan seharian.'),
  ('Menggapai Laut','S. Othman Kelantan','Utusan Publications',1994,116,'Sejarah','Melayu','Karya ini merupakan satu penerokaan mendalam tentang hubungan manusia dengan alam sekitar dan nilai-nilai murni yang terkandung dalam Laut.','Menghargai warisan budaya dan sejarah adalah tanggungjawab setiap generasi untuk masa depan bangsa.'),
  ('Menggapai Gunung','Anwar Ridhwan','Dewan Bahasa dan Pustaka',1995,125,'Agama','Melayu','Sebuah kisah inspirasi yang memaparkan perjuangan seorang tokoh dalam menegakkan kebenaran dan keadilan di sebalik cabaran Gunung.','Ketabahan dan kesabaran adalah kunci kejayaan dalam setiap aspek kehidupan.'),
  ('Menggapai Sungai','Zaharah Nawawi','PTS Publications & Distributors',1996,134,'Sains','Melayu','Novel ini mengisahkan persahabatan yang erat dan nilai-nilai kemanusiaan yang tinggi dalam menghadapi dugaan berkaitan Sungai.','Kasih sayang, perpaduan dan semangat gotong-royong membina masyarakat yang harmoni dan sejahtera.'),
